   287	    fn filter_clip_event(
   288	        self,
   289	        _context: &mut UpdateContext<'gc>,
   290	        event: ClipEvent,
   291	    ) -> ClipEventResult {
   292	        if !self.visible() {
   293	            return ClipEventResult::NotHandled;
   294	        }
   295	
   296	        if !self.enabled() && !matches!(event, ClipEvent::KeyPress { .. }) {
   297	            return ClipEventResult::NotHandled;
   298	        }
   299	
   300	        ClipEventResult::Handled
   301	    }
   302	
   303	    fn propagate_to_children(
   304	        self,
   305	        context: &mut UpdateContext<'gc>,
   306	        event: ClipEvent<'gc>,
   307	    ) -> ClipEventResult {
   308	        if event.propagates() {
   309	            let current_state = self.get_state_child(self.0.state.get().into());
   310	
   311	            if let Some(current_state) = current_state.and_then(|s| s.as_interactive())
   312	                && current_state.handle_clip_event(context, event) == ClipEventResult::Handled
   313	            {
   314	                return ClipEventResult::Handled;
   315	            }
   316	        }
   317	
   318	        ClipEventResult::NotHandled
   319	    }
   320	
   321	    fn event_dispatch(
   322	        self,
   323	        context: &mut UpdateContext<'gc>,
   324	        event: ClipEvent<'gc>,
   325	    ) -> ClipEventResult {
   326	        // Translate the clip event to a button event, based on how the button state changes.
   327	        let shared = self.0.shared.cell.borrow();
   328	        let (new_state, sound) = match event {
   329	            ClipEvent::DragOut { .. } => (ButtonState::Over, None),
   330	            ClipEvent::DragOver { .. } => (ButtonState::Down, None),
   331	            ClipEvent::Press { .. } => (ButtonState::Down, shared.over_to_down_sound.as_ref()),
   332	            ClipEvent::Release { .. } => (ButtonState::Over, shared.down_to_over_sound.as_ref()),
   333	            ClipEvent::ReleaseOutside => (ButtonState::Up, shared.over_to_up_sound.as_ref()),
   334	            ClipEvent::MouseUpInside => (ButtonState::Up, shared.over_to_up_sound.as_ref()),
   335	            ClipEvent::RollOut { .. } => (ButtonState::Up, shared.over_to_up_sound.as_ref()),
   336	            ClipEvent::RollOver { .. } => (ButtonState::Over, shared.up_to_over_sound.as_ref()),
   337	            _ => return ClipEventResult::NotHandled,
   338	        };
   339	
   340	        if let Some((id, sound_info)) = sound {
   341	            AudioManager::perform_sound_event(self.into(), context, *id, sound_info);
   342	        }
   343	        let old_state = self.0.state.get();
   344	
   345	        if old_state != new_state {
   346	            self.set_state(context, new_state);
   347	        }
   348	        ClipEventResult::Handled
   349	    }
