   351	    fn mouse_pick_avm2(
   352	        self,
   353	        context: &mut UpdateContext<'gc>,
   354	        mut point: Point<Twips>,
   355	        require_button_mode: bool,
   356	    ) -> Avm2MousePick<'gc> {
   357	        // The button is hovered if the mouse is over any child nodes.
   358	        if self.visible() && self.mouse_enabled() {
   359	            let state_child = self.get_state_child(self.0.state.get().into());
   360	
   361	            if let Some(state_child) = state_child {
   362	                let mouse_pick = state_child
   363	                    .as_interactive()
   364	                    .map(|c| c.mouse_pick_avm2(context, point, require_button_mode));
   365	                match mouse_pick {
   366	                    None | Some(Avm2MousePick::Miss) => {}
   367	                    // Selecting a child of a button is equivalent to selecting the button itself
   368	                    _ => return Avm2MousePick::Hit(self.into()),
   369	                };
   370	            }
   371	
   372	            if let Some(hit_area) = self.0.hit_area.get() {
   373	                //TODO: the if below should probably always be taken, why does the hit area
   374	                // sometimes have a parent?
   375	                if hit_area.parent().is_none() {
   376	                    // hit_area is not actually a child, so transform point into local space before passing it down.
   377	                    point = if let Some(point) = self.global_to_local(point) {
   378	                        point
   379	                    } else {
   380	                        return Avm2MousePick::Miss;
   381	                    }
   382	                }
   383	                if hit_area.hit_test_shape(context, point, HitTestOptions::MOUSE_PICK) {
   384	                    return Avm2MousePick::Hit(self.into());
   385	                }
   386	            }
   387	        }
   388	        Avm2MousePick::Miss
   389	    }
