```rust
fn invalidate_cached_bitmap(&self) -> bool {
    if self.contains_flag(DisplayObjectFlags::CACHE_INVALIDATED) {
        return false;
    }
    if let Some(cache) = &mut *self.bitmap_cache_mut() {
        cache.make_dirty();
    }
