```rust
fn replace_with(self, context: &mut UpdateContext<'gc>, id: CharacterId) {
    if let Some(new_graphic) = context
        .library
        .library_for_movie_mut(self.movie())
        .get_graphic(id)
    {
        self.set_shared(context.gc(), new_graphic.0.shared.get());
    } else {
